import base64
import hmac
import hashlib

def deserialize_session(cookie: str, secret: bytes) -> dict:
    if not cookie or not secret:
        return {}
    try:
        # Assume cookie is signed with 'sign=sha1 base64-encoded payload'
        try, sep = cookie.split('=', 1)
        if '=' not in cookie:
            return {}
        bdata = base64.b64decode(sep)
        if not bdata:
            return {}
        # Assume signature is first 16 bytes of the data
        sig_b = bdata[:16]
        expected_sig = hmac.new(secret, bdata, hashlib.sha1).digest()
        if not hmac.compare_digest(sig_b, expected_sig):
            return {}
        # Assume the rest is a JSON object
        import json
        try:
            return json.loads(bdata[16:])
        except:
            return {}
    except:
        return {}
